#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,L,R;
        scanf("%d %d %d",&N,&L,&R);
        int result = (N >> R) << L;
        printf("%d\n",result);
    }
    return 0;
}

